//
// Novel (hand-written) command — not regenerated by the press.
//
// Plane's REST issue serializer (both list and retrieve) does NOT include
// module membership: there is no `module_ids` field on an issue payload, so a
// plain `sync` leaves it null everywhere. The only source of truth for "which
// module is this issue in" is the reverse endpoint
//   GET /workspaces/{slug}/projects/{project_id}/modules/{module_id}/module-issues/
// which lists the work items of one module.
//
// The membership enrichment walks every locally-known module, reads its
// module-issues, and (a) populates a `module_issues(module_id, issue_id,
// project_id)` junction table and (b) patches each issue's cached `data` JSON
// with a `module_ids` array. It runs automatically at the tail of `sync` (via
// withModuleEnrichment, wired in root.go) and is also exposed as `module sync`
// for a standalone re-run.
//
// `module create-issue` closes the second gap: Plane's issueCreate body has no
// module field, so an issue can only be put in a module by a second call to
// module-issues. This command does create + add-to-module in one step.

package cli

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"regexp"
	"sort"
	"strings"

	"github.com/mvanhorn/printing-press-library/library/project-management/plane/internal/client"
	"github.com/mvanhorn/printing-press-library/library/project-management/plane/internal/config"
	"github.com/mvanhorn/printing-press-library/library/project-management/plane/internal/store"

	"github.com/spf13/cobra"
)

// applyClientSlug honors an explicit --slug / positional slug by writing it into
// the client's endpoint TemplateVars. PATCH(slug-env-align): the reprinted client
// puts the workspace scope in BaseURL (/api/v1/workspaces/{slug}) and resolves
// {slug} from Config.TemplateVars (seeded from PLANE_SLUG at config load), so the
// novel commands pass workspace-relative paths and set the slug here rather than
// interpolating it into the path themselves.
func applyClientSlug(c *client.Client, slug string) {
	if c == nil || c.Config == nil || slug == "" {
		return
	}
	if c.Config.TemplateVars == nil {
		c.Config.TemplateVars = map[string]string{}
	}
	c.Config.TemplateVars["slug"] = slug
}

// errNoLocalModules signals that the modules table is empty, so there is
// nothing to enrich. The standalone `module sync` command surfaces it as a
// user error; the post-sync hook treats it as a silent no-op.
var errNoLocalModules = errors.New("no modules in local cache")

// issueUUIDPattern validates a work-item id as a canonical UUID. Plane work-item
// ids are always UUIDs, so a non-UUID argument is a user error rather than an
// id that simply isn't in the local cache.
var issueUUIDPattern = regexp.MustCompile(`^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$`)

// moduleGetter is the slice of the API client the enrichment needs. Declared
// locally so this file doesn't depend on the concrete client type.
type moduleGetter interface {
	Get(context.Context, string, map[string]string) (json.RawMessage, error)
}

func newModuleCmd(flags *rootFlags) *cobra.Command {
	cmd := &cobra.Command{
		Use:   "module",
		Short: "Module-membership helpers: cache enrichment (sync) and assign-on-create.",
		Long: `Plane's issue API never returns module membership, so 'sync' would
leave module_ids null on every cached issue. 'sync' now runs this enrichment
automatically; these commands let you re-run it on demand and assign modules
at creation time.

  module sync          Walk modules -> module-issues, populate a module_issues
                       junction table and patch issues.data with module_ids.
                       (Also runs automatically at the end of 'plane-pp-cli sync'.)
  module of <issue>    Show which modules an issue belongs to (from cache).
  module create-issue  Create a work item AND add it to a module in one call.

Workspace slug defaults to $PLANE_SLUG; pass --slug to override.`,
	}
	cmd.AddCommand(newModuleSyncCmd(flags))
	cmd.AddCommand(newModuleOfCmd(flags))
	cmd.AddCommand(newModuleCreateIssueCmd(flags))
	return cmd
}

// ensureModuleIssuesTable creates the junction table if it doesn't exist. It's
// done at runtime rather than in the generated store schema so this novel
// feature survives a press regen without a store.go patch.
func ensureModuleIssuesTable(db *store.Store) error {
	_, err := db.DB().Exec(`CREATE TABLE IF NOT EXISTS module_issues (
		module_id  TEXT NOT NULL,
		issue_id   TEXT NOT NULL,
		project_id TEXT,
		synced_at  DATETIME DEFAULT CURRENT_TIMESTAMP,
		PRIMARY KEY (module_id, issue_id)
	)`)
	if err != nil {
		return err
	}
	_, _ = db.DB().Exec(`CREATE INDEX IF NOT EXISTS idx_module_issues_issue ON module_issues(issue_id)`)
	return err
}

type moduleRow struct {
	id        string
	projectID string
	name      string
}

// localModules reads modules from the synced store, optionally scoped to one
// project. Name comes out of the data JSON.
func localModules(db *store.Store, projectFilter string) ([]moduleRow, error) {
	q := `SELECT id, projects_id, COALESCE(json_extract(data, '$.name'), '') FROM modules`
	var args []any
	if projectFilter != "" {
		q += ` WHERE projects_id = ?`
		args = append(args, projectFilter)
	}
	rows, err := db.Query(q, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []moduleRow
	for rows.Next() {
		var m moduleRow
		if err := rows.Scan(&m.id, &m.projectID, &m.name); err != nil {
			return nil, err
		}
		out = append(out, m)
	}
	return out, rows.Err()
}

// moduleEnrichResult summarizes one enrichment pass.
type moduleEnrichResult struct {
	Modules int
	Links   int
	Patched int
}

// enrichModuleMembership is the shared core used by both the standalone
// `module sync` command and the post-sync hook. It rebuilds the module_issues
// junction table and patches issues.data.module_ids for the given scope.
// Returns errNoLocalModules when the modules table is empty.
func enrichModuleMembership(ctx context.Context, get moduleGetter, db *store.Store, slug, projectFilter string) (moduleEnrichResult, error) {
	var res moduleEnrichResult
	if err := ensureModuleIssuesTable(db); err != nil {
		return res, fmt.Errorf("creating module_issues table: %w", err)
	}
	modules, err := localModules(db, projectFilter)
	if err != nil {
		return res, fmt.Errorf("reading local modules: %w", err)
	}
	if len(modules) == 0 {
		return res, errNoLocalModules
	}
	res.Modules = len(modules)

	pg := determinePaginationDefaults()
	issueToModules := map[string][]string{}

	tx, err := db.DB().Begin()
	if err != nil {
		return res, err
	}
	committed := false
	defer func() {
		if !committed {
			_ = tx.Rollback()
		}
	}()

	// Reset module_ids to [] on all in-scope issues so stale membership is
	// cleared; issues with real membership get overwritten below. Done inside
	// the transaction so a mid-walk failure rolls the reset back instead of
	// leaving every issue's module_ids wiped.
	// PATCH(issues-table-name): the reprinted sync stores issues in the
	// `projects_issues` table (FK `projects_id`), not the old `issues`/`project_id`.
	resetSQL := `UPDATE projects_issues SET data = json_set(data, '$.module_ids', json('[]'))`
	var resetArgs []any
	if projectFilter != "" {
		resetSQL += ` WHERE projects_id = ?`
		resetArgs = append(resetArgs, projectFilter)
	}
	if _, err := tx.Exec(resetSQL, resetArgs...); err != nil {
		return res, fmt.Errorf("resetting module_ids: %w", err)
	}

	for _, m := range modules {
		if _, err := tx.Exec(`DELETE FROM module_issues WHERE module_id = ?`, m.id); err != nil {
			return res, fmt.Errorf("clearing module_issues for %s: %w", m.id, err)
		}
		// PATCH(slug-env-align): workspace-relative path; BaseURL + TemplateVars[slug] supply
		// /api/v1/workspaces/{slug}. The slug param is retained for caller intent/messages.
		path := fmt.Sprintf(
			"/projects/%s/modules/%s/module-issues/",
			m.projectID, m.id,
		)
		cursor := ""
		for {
			params := map[string]string{pg.limitParam: "100"}
			if cursor != "" {
				params[pg.cursorParam] = cursor
			}
			data, gerr := get.Get(ctx, path, params)
			if gerr != nil {
				return res, gerr
			}
			items, next, hasMore := extractPageItems(data, pg.cursorParam)
			for _, raw := range items {
				var obj struct {
					ID string `json:"id"`
				}
				if json.Unmarshal(raw, &obj) != nil || obj.ID == "" {
					continue
				}
				if _, err := tx.Exec(
					`INSERT OR IGNORE INTO module_issues (module_id, issue_id, project_id) VALUES (?, ?, ?)`,
					m.id, obj.ID, m.projectID,
				); err != nil {
					return res, fmt.Errorf("inserting module_issues row: %w", err)
				}
				issueToModules[obj.ID] = append(issueToModules[obj.ID], m.id)
				res.Links++
			}
			if !hasMore || next == "" || len(items) == 0 {
				break
			}
			cursor = next
		}
	}

	for issueID, mods := range issueToModules {
		sort.Strings(mods)
		blob, _ := json.Marshal(uniqueStrings(mods))
		r, uerr := tx.Exec(
			`UPDATE projects_issues SET data = json_set(data, '$.module_ids', json(?)) WHERE id = ?`,
			string(blob), issueID,
		)
		if uerr != nil {
			return res, fmt.Errorf("patching issue %s: %w", issueID, uerr)
		}
		if n, _ := r.RowsAffected(); n > 0 {
			res.Patched++
		}
	}

	if err := tx.Commit(); err != nil {
		return res, fmt.Errorf("commit: %w", err)
	}
	committed = true
	return res, nil
}

// withModuleEnrichment wraps the generated `sync` command so module membership
// is enriched automatically once the regular sync finishes. All logic lives
// here (hand-written) so the only regen-fragile change is the single
// registration line in root.go. Failures are best-effort: they warn but never
// fail the sync, since the core data is already persisted.
func withModuleEnrichment(syncCmd *cobra.Command, flags *rootFlags) *cobra.Command {
	var skip bool
	syncCmd.Flags().BoolVar(&skip, "skip-module-enrich", false, "Skip the automatic post-sync module-membership enrichment pass")
	orig := syncCmd.RunE
	syncCmd.RunE = func(cmd *cobra.Command, args []string) error {
		if orig != nil {
			if err := orig(cmd, args); err != nil {
				return err
			}
		}
		if skip {
			return nil
		}
		slug := resolveSlugFromConfig(flags)
		if slug == "" {
			return nil // sync itself would have failed without a slug
		}
		c, err := flags.newClient()
		if err != nil {
			return nil
		}
		applyClientSlug(c, slug)
		// Honor the --db flag the wrapped sync used, so enrichment writes
		// module_ids into the same store sync just populated (not the default).
		syncDBPath, _ := cmd.Flags().GetString("db")
		if syncDBPath == "" {
			syncDBPath = defaultDBPath("plane-pp-cli")
		}
		db, err := store.OpenWithContext(cmd.Context(), syncDBPath)
		if err != nil {
			return nil
		}
		defer db.Close()
		res, err := enrichModuleMembership(cmd.Context(), c, db, slug, "")
		if err != nil {
			if errors.Is(err, errNoLocalModules) {
				return nil
			}
			fmt.Fprintf(os.Stderr, "warning: module enrichment failed (core sync data is intact): %v\n", err)
			return nil
		}
		if humanFriendly {
			fmt.Fprintf(os.Stderr, "Module membership: %d module(s), %d link(s), %d issue(s) patched.\n", res.Modules, res.Links, res.Patched)
		} else {
			fmt.Fprintf(os.Stdout, `{"event":"module_membership_synced","modules":%d,"links":%d,"issues_patched":%d}`+"\n", res.Modules, res.Links, res.Patched)
		}
		return nil
	}
	return syncCmd
}

func newModuleSyncCmd(flags *rootFlags) *cobra.Command {
	var slug, projectFilter, dbPath string
	cmd := &cobra.Command{
		Use:   "sync",
		Short: "Re-run module-membership enrichment (also runs automatically inside 'plane-pp-cli sync').",
		Long: `Walk every locally-synced module, read its work items via the
module-issues endpoint, and write membership back into the cache:
  - module_issues junction table (module_id, issue_id, project_id)
  - each issue's data JSON gets a module_ids array ([] when in no module)

This runs automatically at the tail of 'plane-pp-cli sync'; use this command to
re-run it on its own or scope it to a single project.`,
		Example: `  plane-pp-cli module sync
  plane-pp-cli module sync --project 8feda17c-6680-4f9d-a485-5cae321cd0cc`,
		RunE: func(cmd *cobra.Command, args []string) error {
			slug = resolveSlug(slug)
			if slug == "" {
				return usageErr(fmt.Errorf("workspace slug not set: pass --slug or export %s", envWorkspaceSlug))
			}
			if dbPath == "" {
				dbPath = defaultDBPath("plane-pp-cli")
			}
			c, err := flags.newClient()
			if err != nil {
				return err
			}
			applyClientSlug(c, slug)
			db, err := store.OpenWithContext(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening local database: %w\nRun 'plane-pp-cli sync' first.", err)
			}
			defer db.Close()

			res, err := enrichModuleMembership(cmd.Context(), c, db, slug, projectFilter)
			if err != nil {
				if errors.Is(err, errNoLocalModules) {
					// No modules cached yet (sync not run, or none in scope): a
					// successful zero-result no-op rather than a hard error, so the
					// command is safe to run anytime and reports clean JSON. The hint
					// goes to stderr to keep stdout machine-parseable.
					fmt.Fprintf(cmd.ErrOrStderr(), "No modules in local cache%s — run 'plane-pp-cli sync' first to populate; nothing to enrich.\n", projectScopeMsg(projectFilter))
					err = nil
				} else if apiErr := classifyAPIError(err, flags); apiErr != nil {
					return apiErr
				} else {
					return err
				}
			}

			if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
				return flags.printJSON(cmd, map[string]any{
					"event":          "module_membership_synced",
					"modules":        res.Modules,
					"links":          res.Links,
					"issues_patched": res.Patched,
					"project_scope":  projectFilter,
				})
			}
			fmt.Fprintf(cmd.OutOrStdout(),
				"Synced module membership: %d module(s), %d link(s), %d issue(s) patched.\n",
				res.Modules, res.Links, res.Patched)
			return nil
		},
	}
	cmd.Flags().StringVar(&slug, "slug", "", "Workspace slug (defaults to $"+envWorkspaceSlug+")")
	cmd.Flags().StringVar(&projectFilter, "project", "", "Limit to one project UUID (default: all synced projects)")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path")
	return cmd
}

func newModuleOfCmd(flags *rootFlags) *cobra.Command {
	var dbPath string
	cmd := &cobra.Command{
		Use:   "of <issue_id>",
		Short: "Show which modules an issue belongs to (from the local cache).",
		Long:  "Reads the module_issues junction table populated by 'module sync'.",
		Example: `  plane-pp-cli module of a1d8592d-7cfc-42a2-adc5-3da1f32b3fb5
  plane-pp-cli module of a1d8592d-7cfc-42a2-adc5-3da1f32b3fb5 --json`,
		Args: cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			if !issueUUIDPattern.MatchString(args[0]) {
				return usageErr(fmt.Errorf("issue_id must be a work-item UUID, got %q", args[0]))
			}
			if dbPath == "" {
				dbPath = defaultDBPath("plane-pp-cli")
			}
			db, err := store.OpenWithContext(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening local database: %w", err)
			}
			defer db.Close()
			// Ensure the junction table exists so a query before any 'module sync'
			// returns an empty result instead of a missing-table error.
			if err := ensureModuleIssuesTable(db); err != nil {
				return fmt.Errorf("preparing module_issues table: %w", err)
			}
			rows, err := db.Query(`
				SELECT mi.module_id, COALESCE(json_extract(m.data, '$.name'), '')
				FROM module_issues mi
				LEFT JOIN modules m ON m.id = mi.module_id
				WHERE mi.issue_id = ?
				ORDER BY 2`, args[0])
			if err != nil {
				return err
			}
			defer rows.Close()
			type modRef struct {
				ID   string `json:"id"`
				Name string `json:"name"`
			}
			var out []modRef
			for rows.Next() {
				var r modRef
				if err := rows.Scan(&r.ID, &r.Name); err != nil {
					return err
				}
				out = append(out, r)
			}
			if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
				return flags.printJSON(cmd, map[string]any{"issue": args[0], "modules": out})
			}
			if len(out) == 0 {
				fmt.Fprintf(cmd.OutOrStdout(), "%s is in no module (or 'module sync' not run yet).\n", args[0])
				return nil
			}
			for _, r := range out {
				fmt.Fprintf(cmd.OutOrStdout(), "%s  %s\n", r.ID, r.Name)
			}
			return nil
		},
	}
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path")
	return cmd
}

func newModuleCreateIssueCmd(flags *rootFlags) *cobra.Command {
	var name, descriptionHTML, priority, state, parent, startDate, targetDate string
	var assignees, labels string
	var point int
	var dbPath string
	cmd := &cobra.Command{
		Use:   "create-issue <module_id> <project_id> <slug>",
		Short: "Create a work item and add it to a module in one step.",
		Long: `Plane's issueCreate body has no module field, so assigning a module
otherwise needs two manual calls. This does both: POST the issue, then POST it
to the module's module-issues endpoint. On success it also patches the local
cache (module_issues) if the issue store is present.`,
		Example: `  plane-pp-cli module create-issue <module_id> <project_id> <workspace-slug> \
    --name "Wire OIDC callback" --priority high --state <state_id>`,
		Args: cobra.MinimumNArgs(3),
		RunE: func(cmd *cobra.Command, args []string) error {
			moduleID, projectID, slug := args[0], args[1], args[2]
			if name == "" && !flags.dryRun {
				return usageErr(fmt.Errorf("--name is required"))
			}
			c, err := flags.newClient()
			if err != nil {
				return err
			}
			applyClientSlug(c, slug)

			body := map[string]any{"name": name}
			if descriptionHTML != "" {
				body["description_html"] = descriptionHTML
			}
			if priority != "" {
				body["priority"] = priority
			}
			if state != "" {
				body["state"] = state
			}
			if parent != "" {
				body["parent"] = parent
			}
			if startDate != "" {
				body["start_date"] = startDate
			}
			if targetDate != "" {
				body["target_date"] = targetDate
			}
			if point != 0 {
				body["point"] = point
			}
			if assignees != "" {
				var parsed any
				if err := json.Unmarshal([]byte(assignees), &parsed); err != nil {
					return fmt.Errorf("parsing --assignees JSON: %w", err)
				}
				body["assignees"] = parsed
			}
			if labels != "" {
				var parsed any
				if err := json.Unmarshal([]byte(labels), &parsed); err != nil {
					return fmt.Errorf("parsing --labels JSON: %w", err)
				}
				body["labels"] = parsed
			}

			// PATCH(slug-env-align): workspace-relative paths; {slug} resolved from the client TemplateVars set above.
			issuePath := fmt.Sprintf("/projects/%s/issues/", projectID)
			modulePath := fmt.Sprintf("/projects/%s/modules/%s/module-issues/", projectID, moduleID)

			if flags.dryRun {
				return flags.printJSON(cmd, map[string]any{
					"dry_run":     true,
					"step_1_post": issuePath,
					"step_1_body": body,
					"step_2_post": modulePath,
					"step_2_body": map[string]any{"issues": []string{"<new_issue_id>"}},
				})
			}

			created, _, err := c.Post(cmd.Context(), issuePath, body)
			if err != nil {
				return classifyAPIError(err, flags)
			}
			issueID := extractCreatedIssueID(created)
			if issueID == "" {
				return fmt.Errorf("issue created but could not parse its id from response: %s", string(created))
			}

			if _, _, err := c.Post(cmd.Context(), modulePath, map[string]any{"issues": []string{issueID}}); err != nil {
				return fmt.Errorf("issue %s created but adding to module failed: %w", issueID, classifyAPIError(err, flags))
			}

			// Best-effort local cache update so 'module of' is correct without a
			// full re-sync. Silently skipped if the store isn't initialized.
			if dbPath == "" {
				dbPath = defaultDBPath("plane-pp-cli")
			}
			if db, derr := store.OpenWithContext(cmd.Context(), dbPath); derr == nil {
				defer db.Close()
				if ensureModuleIssuesTable(db) == nil {
					_, _ = db.DB().Exec(
						`INSERT OR IGNORE INTO module_issues (module_id, issue_id, project_id) VALUES (?, ?, ?)`,
						moduleID, issueID, projectID)
				}
			}

			if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
				return flags.printJSON(cmd, map[string]any{
					"event":    "issue_created_in_module",
					"issue_id": issueID,
					"module":   moduleID,
					"project":  projectID,
				})
			}
			fmt.Fprintf(cmd.OutOrStdout(), "Created issue %s and added to module %s.\n", issueID, moduleID)
			return nil
		},
	}
	cmd.Flags().StringVar(&name, "name", "", "Work item title (required)")
	cmd.Flags().StringVar(&descriptionHTML, "description-html", "", "Description (HTML)")
	cmd.Flags().StringVar(&priority, "priority", "", "urgent | high | medium | low | none")
	cmd.Flags().StringVar(&state, "state", "", "Workflow state UUID")
	cmd.Flags().StringVar(&parent, "parent", "", "Parent work item UUID (sub-issue)")
	cmd.Flags().StringVar(&startDate, "start-date", "", "Start date (YYYY-MM-DD)")
	cmd.Flags().StringVar(&targetDate, "target-date", "", "Target date (YYYY-MM-DD)")
	cmd.Flags().IntVar(&point, "point", 0, "Estimate point")
	cmd.Flags().StringVar(&assignees, "assignees", "", "Assignee UUIDs as a JSON array, e.g. '[\"uuid\"]'")
	cmd.Flags().StringVar(&labels, "labels", "", "Label UUIDs as a JSON array")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (for local cache update)")
	return cmd
}

// resolveSlugFromConfig mirrors the generated sync command's slug resolution:
// the config file's TemplateVars["slug"] first (populated from PLANE_SLUG at
// load time), then a live PLANE_SLUG env override. PATCH(slug-env-align): the
// reprinted client stores the workspace {slug} in Config.TemplateVars rather
// than a dedicated WorkspaceSlug field.
func resolveSlugFromConfig(flags *rootFlags) string {
	slug := ""
	if cfg, err := config.Load(flags.configPath); err == nil {
		slug = cfg.TemplateVars["slug"]
	}
	if v := os.Getenv(envWorkspaceSlug); v != "" {
		slug = v
	}
	return slug
}

// extractCreatedIssueID pulls the id out of an issueCreate response, tolerating
// both a bare object and an enveloped {"data":{...}} / {"results":{...}} shape.
func extractCreatedIssueID(data json.RawMessage) string {
	var bare struct {
		ID   string `json:"id"`
		Data struct {
			ID string `json:"id"`
		} `json:"data"`
		Results struct {
			ID string `json:"id"`
		} `json:"results"`
	}
	if json.Unmarshal(data, &bare) != nil {
		return ""
	}
	switch {
	case bare.ID != "":
		return bare.ID
	case bare.Data.ID != "":
		return bare.Data.ID
	case bare.Results.ID != "":
		return bare.Results.ID
	}
	return ""
}

func uniqueStrings(in []string) []string {
	seen := map[string]bool{}
	var out []string
	for _, s := range in {
		if !seen[s] {
			seen[s] = true
			out = append(out, s)
		}
	}
	return out
}

func projectScopeMsg(projectFilter string) string {
	if projectFilter == "" {
		return ""
	}
	return " for project " + strings.TrimSpace(projectFilter)
}
